INSERT INTO `v1_7922d96e492bb94527b926bd2a6f9069993b02799129cea59e62aca9ba40618a` VALUES (12300150, "vo_minigame_1012_result_1082", 3001, 1, 9, 3, "ん～はっきり言って微妙ね！\nま、難しい問題だし、\n勉強すれば\n点数は上がっていくと思うわ！", 2.46, 2, 2, 5, 1, 0);
INSERT INTO `v1_7922d96e492bb94527b926bd2a6f9069993b02799129cea59e62aca9ba40618a` VALUES (12300151, "vo_minigame_1012_result_1083", 3001, 1, 9, 3, "ん～…\n10点には届かなかったか～\n次は10点越え目指して\n頑張ってみない？", 2.94, 2, 2, 5, 1, 0);
INSERT INTO `v1_7922d96e492bb94527b926bd2a6f9069993b02799129cea59e62aca9ba40618a` VALUES (12300152, "vo_minigame_1012_result_1084", 3001, 1, 9, 7, "はいお疲れ～\n点数的にはまあまあってとこね！\nま、超難問だし頑張ったわよ", 4.19, 3, 2, 5, 1, 0);
INSERT INTO `v1_7922d96e492bb94527b926bd2a6f9069993b02799129cea59e62aca9ba40618a` VALUES (12300153, "vo_minigame_1012_result_1085", 3001, 1, 9, 1, "うん、かなり難しい問題なのに\n最後までやり遂げたわね\n次はもっといい点目指してみる？", 0.0, 3, 2, 5, 1, 0);
INSERT INTO `v1_7922d96e492bb94527b926bd2a6f9069993b02799129cea59e62aca9ba40618a` VALUES (12300154, "vo_minigame_1012_result_1086", 3001, 1, 9, 3, "ちょっとミスが多かったかもね～\nでも間違えた所は復習して\n次は正解するわよー！", 2.63, 3, 2, 5, 1, 0);
