INSERT INTO `v1_7922d96e492bb94527b926bd2a6f9069993b02799129cea59e62aca9ba40618a` VALUES (12300156, "vo_minigame_1012_result_1088", 3001, 3, 4, 3, "ん～…正解数は\n物足りないわね～\nもうちょっと勉強の時間\n増やしちゃおっか？", 0.01, 1, 2, 1, 1, 9);
INSERT INTO `v1_7922d96e492bb94527b926bd2a6f9069993b02799129cea59e62aca9ba40618a` VALUES (12300157, "vo_minigame_1012_result_1089", 3001, 1, 4, 3, "ん～…あんたならもうちょと\nいい点取れんでしょ～？\nもっと頑張んなさいよ\n期待してやってんだからさ！", 4.15, 1, 2, 1, 1, 3);
INSERT INTO `v1_7922d96e492bb94527b926bd2a6f9069993b02799129cea59e62aca9ba40618a` VALUES (12300158, "vo_minigame_1012_result_1090", 3001, 9, 4, 9, "ん～今のあんたには、\nこの問題は難しかったかしら…\n難易度下げてチャレンジするのも\nありかもね～？", 0.01, 2, 2, 1, 1, 9);
INSERT INTO `v1_7922d96e492bb94527b926bd2a6f9069993b02799129cea59e62aca9ba40618a` VALUES (12300159, "vo_minigame_1012_result_1091", 3001, 1, 4, 3, "あんまり出来は良くないわね～\n難しい問題だししょうがないけど\n次はもっと頑張ってほしいわ！", 5.37, 2, 2, 1, 1, 0);
INSERT INTO `v1_7922d96e492bb94527b926bd2a6f9069993b02799129cea59e62aca9ba40618a` VALUES (12300160, "vo_minigame_1012_result_1092", 3001, 1, 4, 3, "なるほど…\nちょっと苦手な問題が多かった？\nもう一度チャレンジ\nしてみましょうか～", 1.44, 2, 2, 1, 1, 0);
