INSERT INTO `v1_7922d96e492bb94527b926bd2a6f9069993b02799129cea59e62aca9ba40618a` VALUES (12300163, "vo_minigame_1012_result_1095", 3001, 1, 4, 5, "ごめん、ちょっと難しすぎた？\nもう一度チャレンジするも良し、\n難易度を下げるも良し、\nあんたがやる気なら付き合うわ！", 2.61, 3, 2, 1, 1, 0);
INSERT INTO `v1_7922d96e492bb94527b926bd2a6f9069993b02799129cea59e62aca9ba40618a` VALUES (12300164, "vo_minigame_1012_result_1096", 3001, 2, 0, 4, "ちょっとあんた…\nやる気ないわよね～！？\n次こんな点数取ったら\n怒るわよ！", 3.63, 1, 2, 0, 1, 1);
